SELECT species, approx_trees, est_vol_32_log, estimated_vol_price
FROM timber_inventory
WHERE site_id = 1;

SELECT AVG(appraised_price_per_mbf) AS avg_appraised_price
FROM timber_inventory
WHERE condition = 'good';

SELECT appraiser_name, specialization
FROM appraisers
WHERE years_of_experience > 10;

SELECT COUNT(*) 
FROM appraisals
WHERE status = 'completed';

SELECT appraisal_date, appraised_value
FROM appraisals
WHERE appraiser_id = 1;

SELECT species, estimated_vol_price
FROM timber_inventory
ORDER BY estimated_vol_price DESC;

SELECT species, approx_trees
FROM timber_inventory
WHERE site_id = (SELECT site_id FROM sites WHERE site_name = 'Southeast Logging Area');
